INSERT INTO `comments` (`id`, `post_id`, `user_name`, `content`, `timestamp`) VALUES
(1, 'Srujan checking title limits and length. word 12345678910', 'Anonymous', 'Nice work', '2026-04-21 08:56:47'),
(2, 'Sampath Kumar Charandas: Navigating Real Estate with Precision', 'Syed Moiz', 'A real inspiration! 🙌\n\nThe way Sir handles clients, manages situations, and closes challenges with confidence is simply outstanding. His commitment and sales skills turn the impossible into success stories. 🔥', '2026-05-11 14:13:47'),
(3, 'Sampath Kumar Charandas: Navigating Real Estate with Precision', 'Anonymous', 'I remember my first meeting with Sam anna. What impressed me the most was his clarity of thoughts and how honestly he spoke. He is a mentor and brother to us all, who is always ears for our troubles and always there to guide.', '2026-05-11 15:00:01'),
(4, 'Sampath Kumar Charandas: Navigating Real Estate with Precision', 'Anupam Shrivastava', 'Great to see the journey and thought process behind building something impactful. Consistency, trust and dedication truly reflect in such success stories. Wishing the team many more milestones ahead.', '2026-05-11 15:00:34'),
(5, 'Sampath Kumar Charandas: Navigating Real Estate with Precision', 'Rebba praveen kumar', 'The way you embarked on your journey—along with your disciplined approach—serves as an exemplary model for everyone. It is truly a pleasure to witness the journey and the mindset behind the creation of such a brilliant and impactful enterprise. Your unwavering fairness, trustworthiness, and dedication toward your customers are clearly reflected in success stories such as this one. I sincerely hope that this team achieves many more milestones in the future.', '2026-05-11 17:56:27'),
(6, 'Sampath Kumar Charandas: Navigating Real Estate with Precision', 'Srinivas Peram', 'Sampath, huge appreciation for the way you’re building Nandaka Asset Advisory with such dedication and expertise. The value you create for your clients is evident, and it’s inspiring to see your journey. May Nandaka scale new heights and become a name everyone trusts. Keep going strong', '2026-05-12 08:11:48'),
(7, 'Sampath Kumar Charandas: Navigating Real Estate with Precision', 'Sudeep', 'Boss is always right 👍💯', '2026-05-12 11:08:30'),
(8, 'Sampath Kumar Charandas: Navigating Real Estate with Precision', 'Sudeep', 'Boss is always right 👍💯', '2026-05-14 05:20:49'),
(9, 'Bridging Asian Brands to Global Markets  ', 'Anonymous', 'Nice, your determination to help is amazing.', '2026-05-20 07:26:19'),
(10, 'Turning Waste Into Worth: The Story of Raghuram Natarajan and Green Recykloplast', 'gurudutt', 'Amazing work being done', '2026-05-21 02:11:40'),
(11, 'No Funding. No Team. Just Her And A Dream.', 'Rakesh Sampathi', 'Proud of you girl, you&#039;re one of my inspirations to plan to start micro businesses and persue our dreams. At present I don&#039;t have funds to start but very soon I&#039;ll definitely start. Keep inspiring. Thankyou.', '2026-05-21 05:39:29'),
(12, 'No Funding. No Team. Just Her And A Dream.', 'Sai Naidu', '😎', '2026-05-21 16:25:38'),
(13, 'Shyam Sankeerth Gupta: Rejected Twice, Accepted Everywhere', 'Anonymous', 'Excellent 👌👌👌', '2026-05-22 10:34:52'),
(14, 'Shyam Sankeerth Gupta: Rejected Twice, Accepted Everywhere', 'Srilatha', 'Congratulations shyam  🎉', '2026-05-22 11:13:36'),
(15, 'Shyam Sankeerth Gupta: Rejected Twice, Accepted Everywhere', 'Tara', 'Congratulations Shyam 👏🏻\nWell deserved 🙌', '2026-05-22 19:11:15'),
(16, 'How Supritha Sri Turned Passion Into Minsu Bakehouse', 'Sindhuja', 'Her journey felt personal seeing her do so much hardwork,  chasing her dreams , Accepting failures what not  everything. Just fell in love each time she comes and share things about her business . Her graph was never straight yet she managed.. from playing with her to seeing her grew this much i felt happy but tackling everything on way is what makes her more special . She taught me consistency could always be the key it might not  work  today but someday for sure. So  no doubt always Minsu ❤️🧿', '2026-05-25 06:20:11'),
(17, 'How Supritha Sri Turned Passion Into Minsu Bakehouse', 'Meghana', 'Watching her build everything step by step has honestly been so beautiful to see.\nThere were failures, pressure, tough phases and so much hard work behind it all, but she still kept going.\nFrom college days to seeing her grow into someone this strong and dedicated makes me really proud.\nShe truly showed that even if things take time, consistency never goes waste… always Minsu 🫶', '2026-05-25 08:22:11'),
(18, 'How Supritha Sri Turned Passion Into Minsu Bakehouse', 'Tejasvini', 'I am very proud of my friend who chose her passion over conventional path.She is an inspiration to all of us.Her optimistic mentality, persistent efforts and consistency are inspirational.I wish she achieves all her dreams and she keeps inspiring us.Minsu is built with so much love and hope.So do order from minsu and make your tummy happy ❤️', '2026-05-25 08:25:29'),
(19, 'How Supritha Sri Turned Passion Into Minsu Bakehouse', 'SaiSri reddy', 'I’m so happy for you! It’s wonderful to see you finally build something you’ve wanted to do for a long time. Pursuing your passions at a young age is incredibly important. There’s still a long way to go, but I have no doubt that you’ll continue to grow, gain more power, and achieve greater success. I wish you all the best and am incredibly proud of you.', '2026-05-25 08:28:19'),
(20, 'How Supritha Sri Turned Passion Into Minsu Bakehouse', 'D.S.Rao', 'Good keep going,All the best 👍', '2026-05-25 09:04:22'),
(21, 'How Supritha Sri Turned Passion Into Minsu Bakehouse', 'Anonymous', 'Wishing you all the best🌸.. proving passion knows no age..', '2026-05-25 09:08:39'),
(22, 'How Supritha Sri Turned Passion Into Minsu Bakehouse', 'Pendyala Thrishul', 'I’ve known Supritha Sri since her childhood, and it has been truly inspiring to watch her grow into such a talented and dedicated baking professional. Her passion for cake making and baking reflects in every creation she makes. She combines creativity, precision, and professionalism beautifully, delivering cakes that are not only visually stunning but also delicious.\nSupritha Sri is hardworking, detail-oriented, and always committed to maintaining high quality in her work. Her ability to understand customer preferences and turn ideas into elegant cake designs is remarkable. Over the years, she has developed excellent skills in baking, decoration, and presentation, making her stand out in the caking and baking field.\nI highly appreciate her dedication, positive attitude, and continuous effort to improve her craft. I confidently recommend her to anyone looking for a skilled and professional baker who puts heart and creativity into every order.', '2026-05-25 09:16:40'),
(23, 'Making Every Client Feel Like a Celebrity Through Thoughtful Event Design', 'M Madhavi', 'I highly recommend Celebrity Events. They deliver what they promise. Your vision becomes their ambition... I&#039;ve seen their efforts, creativity and dedication in many events that I attended. Deeptimam has an outstanding ability to manage and make it all happen. To get a event management company which puts customers&#039; requirements and wishes on priorities and deliver it and every time by proving how Celebrity Events is best in the industry, I wish all the best, immense wishes and godspeed success to Celebrity Events going ahead. Thanks SW for recognising the true potential of rising entrepreneurs.', '2026-05-25 10:18:10'),
(24, 'How Supritha Sri Turned Passion Into Minsu Bakehouse', 'Tejaswi', 'You will always make us proud and your journey is truly inspiring. From day 1 you stood up for building this with lot of passion and love. I feel so happy for you and many more on your way❤️.', '2026-05-25 13:39:21'),
(25, 'How Supritha Sri Turned Passion Into Minsu Bakehouse', 'Swathi', 'Supritha, seeing you chase your dreams and build something so beautiful with your own passion and hard work honestly makes me admire you even more. From day one, the love and dedication you put into your bakery has been truly inspiring. ✨\n\nChoosing your own path in business takes courage, and you’re doing it so gracefully. Every small step you take is turning into something amazing, and I know this is only the beginning of many bigger successes waiting for you.\n\nI’m genuinely so happy and proud to see you grow, shine, and create happiness through your cakes. Keep believing in yourself always — you’re meant for wonderful things ❤️🎂', '2026-05-26 08:17:16'),
(26, 'How Anand Vishwanath Built Alkaione', 'Narendra Nath Gunda', 'Proud of your acheivments Anand. Best product at best Price.', '2026-05-26 09:12:47'),
(27, 'How Anand Vishwanath Built Alkaione', 'Aravind Gullapalli', 'Truly appreciate your vision and commitment to deliver Valuable products in health and wellness', '2026-05-26 09:42:50'),
(28, 'How Anand Vishwanath Built Alkaione', 'Sunnapu Sreedhar', 'Dear Anand,                                              Just went through the article on Alkaione and I must say it is truly inspiring. What impressed me the most is not just the technology, but the vision behind it, redefining water itself as a foundation for wellness and healthy living.\n\nBuilding something innovative is one thing, but creating awareness and changing mindsets is a completely different challenge, and you seem to be doing both with great passion and conviction. Your journey from identifying a gap in the market to building a purpose driven brand across India is commendable.\n\nWishing you and Alkaione even greater success in the coming years. Proud to see a friend creating such meaningful impact in people’s lives. Keep inspiring and keep growing. Best wishes always!', '2026-05-26 09:45:23'),
(29, 'How Anand Vishwanath Built Alkaione', 'Dr.Reshma Nilak', 'Thank you Anand for Alkione\nI have been using since 4 years and i can say it works wonder.\nBest wishes to Anand and whole Alkione team\nGod bless and keep it up\nYou deserve soo much more', '2026-05-26 09:49:34'),
(30, 'How Anand Vishwanath Built Alkaione', 'Balaram V', 'Your vision for wellness of people is admirable. You and your team worked hard and developed accurate pH level water deliver machine Alkaione which is beyond pure water. This is helping in many health issues eradicating them and hydrating with required pH for wellbeing. I trust in God Your product reach to many more persons. \n\nI am well satisfied by your Alkaione water ioniser machine improving my energy at my age 68 years. God bless your product sale grow with new heights🙌', '2026-05-26 11:50:43'),
(31, 'How Anand Vishwanath Built Alkaione', 'Naveen Kumar', 'Great feeling when the hard work pays off and the product is finally thriving. \nHappy for you Mr.Anand and your product M/s Alkaione', '2026-05-27 05:25:43'),
(32, 'How Anand Vishwanath Built Alkaione', 'Premanand C Alakursi', 'I know Mr. Anand since a decade he is a smart businessman, who plans to reach his goals. A good visionary leader and mentor. One of the perfect model for upcoming generations.', '2026-05-27 05:36:50'),
(33, 'How Anand Vishwanath Built Alkaione', 'Dhondi Nageshwar', 'May I know your products and the parameters of water developed.', '2026-05-27 06:35:24');
INSERT INTO `featured_submissions` (`id`, `type`, `full_name`, `role`, `email`, `phone`, `company_name`, `company_website`, `company_linkedin`, `company_email`, `form_data`, `status`, `created_at`, `post_id`) VALUES
(25, 'founders_unfiltered', 'Prasanth ', 'CEO ', 'mslakshmitiles@gmail.com', '+91 96189 99609', 'Lakshmi Tiles', 'https://www.lakshmitiles.in/', 'https://linkedin.com/company/example', 'mslakshmitiles@gmail.com', '{\"q1\":\"I am Prasanth Vinnakota and I am an MBA from Gitam University\",\"q2\":\"I am building clay tiles, bringing back old tradition and legacy. \",\"q3\":\"Natural cooling and climate changes, environmental concern, clay tiles represent our ancestral roots and tradition. \",\"q4\":\"talking to clients, understanding their requirements and building designs, looking at operations \",\"q5\":\"Hi \",\"q6\":\"Motivation, challges, overcomming strugles, labour intese work, so need to communicate with them \",\"q7\":\"labour and govt not supporting \",\"q8\":\"nothing much\\r\\n\",\"q9\":\"Just start and never look back. \",\"q10\":\"hard, brain rotting \",\"q11\":\"Business is not as easy as it looks; manufacturing is not easy, managing labour is not easy, finding business and motivating people to and go organic, tredintal is not easy. \"}', 'approved', '2026-05-25 11:13:52', 46);
